# ❌ ANTI-PATTERN: Reprocessing identical context
for match in cricket_tournaments:
    prompt = f"Analyze {STATIC_RULES} and {match['data']}"  # Recomputing STATIC_RULES every time
    response = client.messages.create(model="claude-3-5-sonnet", messages=[{"role": "user", "content": prompt}])
    print(response.content[0].text)

# ✅ BEST PRACTICE: Prompt caching with cache_control
STATIC_RULES = "Cricket scoring: 6 runs if ball clears boundary in air, 4 if on ground..."

for match in cricket_tournaments:
    response = client.messages.create(
        model="claude-3-5-sonnet",
        system=[
            {
                "type": "text",
                "text": STATIC_RULES,
                "cache_control": {"type": "ephemeral"}  # Cache this context
            }
        ],
        messages=[{
            "role": "user",
            "content": f"Analyze this match performance: {match['data']}"
        }]
    )
    print(f"Cache creation: {response.usage.cache_creation_input_tokens}")
    print(f"Cache read: {response.usage.cache_read_input_tokens}")  # Should be > 0 on subsequent calls

# ❌ ANTI-PATTERN: Processing requests one-by-one for latency-insensitive tasks
analysis_results = []
for player in cricket_squad:
    result = client.messages.create(
        model="claude-3-5-sonnet",
        messages=[{"role": "user", "content": f"Rate {player['name']}'s form"}]
    )
    analysis_results.append(result.content[0].text)

# ✅ BEST PRACTICE: Batch processing for non-interactive workloads
batch_requests = [
    {
        "custom_id": f"player-{player['id']}",
        "params": {
            "model": "claude-3-5-sonnet",
            "messages": [{"role": "user", "content": f"Rate {player['name']}'s form"}]
        }
    }
    for player in cricket_squad
]

batch_job = client.beta.messages.batches.create(requests=batch_requests)
print(f"Batch submitted: {batch_job.id}")
# Poll for completion, then retrieve results—90% cost savings
